samples.input:
module simple_reg(
    input clk,
    input rst,
    input [7:0] din,
    output reg [7:0] dout
);
    always @(posedge clk or posedge rst) begin
        if (rst)
            dout <= 8'b0;
        else
            dout <= din;
    end
endmodule

samples.output:
module simple_reg_tmr(
    input clk,
    input rst,
    input [7:0] din,
    output reg [7:0] dout
);
    wire [7:0] dout_A, dout_B, dout_C;

    simple_reg inst_A(.clk(clk), .rst(rst), .din(din), .dout(dout_A));
    simple_reg inst_B(.clk(clk), .rst(rst), .din(din), .dout(dout_B));
    simple_reg inst_C(.clk(clk), .rst(rst), .din(din), .dout(dout_C));

    majority_voter_8bit voter(
        .A(dout_A),
        .B(dout_B),
        .C(dout_C),
        .Z(dout)
    );
endmodule

